+
+        ServiceHeader.Get("Document Type", "Document No.");
+        ServiceHeader2 := ServiceHeader;
+        if ServiceHeader.Status <> RepairStatus3."Service Order Status" then begin
+            ServiceHeader.SetValidatingFromLines(true);
